// Basic structure of module-info.java
module com.example.myapp {
    requires java.sql;
    exports com.example.myapp.api;
}

// Example of a module definition
module com.example.app {
    // Depends on the java.sql module
    requires java.sql;
    // Depends on the java.logging module
    requires java.logging;

    // Exposes the api package to external modules
    exports com.example.app.api;
    // The internal package is not exported (inaccessible from outside)
}

