// java.base is automatically required, so
// the following two are equivalent
module com.example.app {
    // requires java.base; // Not needed (implicit)
    requires java.sql;
}

// java.lang, java.util, java.io are
// included in java.base and always available
import java.util.List;      // OK
import java.io.IOException; // OK

module com.example.app {
    // Required for database access
    requires java.sql;
    // Required for logging functionality
    requires java.logging;
    // Required for GUI development
    requires java.desktop;

    exports com.example.app.api;
}

